SELECT COUNT(*) FROM USER_MASTER WHERE 1=1
AND USER_NM LIKE CONCAT('%', #{schUserNm}, '%')
AND USER_STAT = #{schUserStat}

mapper.update:
UPDATE
	USER_MASTER
SET
	USER_MAIL = #{userMail}
  , USER_NM = #{userNm}
  , USER_PW = #{userPw}
  , USER_STAT = #{userStat}
  , USER_NOTE = #{userNote}
  
  	, PROFILE_IMG = (
				  		SELECT
				  			MAX(FILE_NO)
				  		FROM
				  			FILE_MASTER
				  	)
  
  , UP_NO = '1'
  , UP_DATE = NOW()
WHERE
		1=1

	AND USER_IDX = #{userIdx}
